/**
 * Theme type definitions and built-in theme data for T3 Code.
 *
 * This module is consumed by the web app for theme application and by any
 * other consumer that needs to reason about theme identifiers or preview colors.
 *
 * The `ThemeColors` values are concrete hex/color strings used exclusively for
 * swatch previews in the UI — they are NOT applied as CSS custom properties.
 * Actual CSS variable values are defined per-theme in apps/web/src/index.css.
 */

/** Semantic color slots used to render theme preview swatches. */
export interface ThemeColors {
  /** Main app background color. */
  background: string;
  /** Main text / foreground color. */
  foreground: string;
  /** Primary accent / highlight color. */
  accent: string;
  /** Sidebar panel background color. */
  sidebar: string;
  /** Editor / code area background color. */
  editor: string;
  /** Terminal emulator background color. */
  terminal: string;
  /** Status bar background color. */
  statusBar: string;
}

/** Metadata and preview colors for a built-in named theme. */
export interface BuiltInTheme {
  /** Unique identifier applied as the `data-theme` attribute on `<html>`. */
  id: ThemeId;
  /** Human-readable display name shown in the theme selector. */
  name: string;
  /** Whether this theme uses dark-mode styles (controls the `.dark` class). */
  isDark: boolean;
  /** Concrete color strings for swatch previews — not applied to the page. */
  colors: ThemeColors;
}

/** The set of named theme identifiers supported by the application. */
export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/**
 * A stored theme preference. Either a named theme ID or `"system"` which
 * resolves to `"t3-dark"` or `"t3-light"` based on the OS color-scheme preference.
 */
export type ThemePreference = ThemeId | "system";

/** All built-in themes in display order (light → dark → midnight). */
export const BUILT_IN_THEMES: ReadonlyArray<BuiltInTheme> = [
  {
    id: "t3-light",
    name: "T3 Light",
    isDark: false,
    colors: {
      background: "#ffffff",
      foreground: "#2a2a2a",
      accent: "#4338ca",
      sidebar: "#f5f5f5",
      editor: "#fafafa",
      terminal: "#1e1e1e",
      statusBar: "#4338ca",
    },
  },
  {
    id: "t3-dark",
    name: "T3 Dark",
    isDark: true,
    colors: {
      background: "#0d0d0f",
      foreground: "#f5f5f5",
      accent: "#7c6fff",
      sidebar: "#111113",
      editor: "#0f0f11",
      terminal: "#0d0d0f",
      statusBar: "#7c6fff",
    },
  },
