import { useCallback, useEffect, useSyncExternalStore } from "react";
import { BUILT_IN_THEMES, type ThemeId, type ThemePreference } from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

// ---------------------------------------------------------------------------
// Storage migration: upgrade old "light" / "dark" values to the new theme IDs.
// Must run before the first applyTheme() call to avoid FOUC for existing users.
// ---------------------------------------------------------------------------
function migrateStoredTheme(): void {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw === "light") {
      localStorage.setItem(STORAGE_KEY, "t3-light");
    } else if (raw === "dark") {
      localStorage.setItem(STORAGE_KEY, "t3-dark");
    }
    // "system" and the new theme IDs need no migration.
  } catch {
    // Ignore storage errors.
  }
}

// ---------------------------------------------------------------------------
// State
// ---------------------------------------------------------------------------
let listeners: Array<() => void> = [];
type ThemeSnapshot = { preference: ThemePreference; themeId: ThemeId; systemDark: boolean };
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

const VALID_PREFERENCES = new Set<string>(["system", ...BUILT_IN_THEMES.map((t) => t.id)]);

function getStored(): ThemePreference {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw !== null && VALID_PREFERENCES.has(raw)) return raw as ThemePreference;
  } catch {
    // Ignore storage errors.
  }
  return "system";
}

function resolveThemeId(preference: ThemePreference): ThemeId {
  if (preference === "system") {
    return getSystemDark() ? "t3-dark" : "t3-light";
  }
  return preference;
}

// ---------------------------------------------------------------------------
// DOM application
// ---------------------------------------------------------------------------
function applyTheme(preference: ThemePreference, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
    // Force a reflow so no-transitions takes effect before the attribute change.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
  }

  const themeId = resolveThemeId(preference);
  const theme = BUILT_IN_THEMES.find((t) => t.id === themeId);
  const isDark = theme?.isDark ?? false;

  document.documentElement.setAttribute("data-theme", themeId);
  document.documentElement.classList.toggle("dark", isDark);

  if (suppressTransitions) {
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// ---------------------------------------------------------------------------
// Module-load side effects (order matters for FOUC prevention)
// ---------------------------------------------------------------------------
migrateStoredTheme();
applyTheme(getStored());

// ---------------------------------------------------------------------------
// useSyncExternalStore plumbing
// ---------------------------------------------------------------------------
function getSnapshot(): ThemeSnapshot {
  const preference = getStored();
  const themeId = resolveThemeId(preference);
  const systemDark = preference === "system" ? getSystemDark() : false;

  if (
    lastSnapshot !== null &&
    lastSnapshot.preference === preference &&
    lastSnapshot.themeId === themeId &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { preference, themeId, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // React to OS color-scheme changes when preference is "system".
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleMediaChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleMediaChange);

  // React to theme changes made in other browser tabs.
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleMediaChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------
export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { preference, themeId } = snapshot;

  /**
   * Backward-compatible resolved theme string: always "light" or "dark".
   * Consumed by ChatView, DiffPanel, DiffWorkerPoolProvider, ChatMarkdown,
   * ComposerPromptEditor, and resolveDiffThemeName() — do not change the type.
   */
  const resolvedTheme: "light" | "dark" = (() => {
    const theme = BUILT_IN_THEMES.find((t) => t.id === themeId);
    return theme?.isDark ? "dark" : "light";
  })();

  const setTheme = useCallback((next: ThemePreference) => {
    try {
      localStorage.setItem(STORAGE_KEY, next);
    } catch {
      // Ignore storage errors.
    }
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync if the snapshot changes (e.g. system preference update).
  useEffect(() => {
    applyTheme(preference);
  }, [preference]);

  return { theme: preference, themeId, setTheme, resolvedTheme } as const;
}

