import { BUILT_IN_THEMES, type ThemePreference } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

// ---------------------------------------------------------------------------
// Swatch
// ---------------------------------------------------------------------------

interface ThemeSwatchProps {
  background: string;
  sidebar: string;
  accent: string;
  statusBar: string;
}

function ThemeSwatch({ background, sidebar, accent, statusBar }: ThemeSwatchProps) {
  return (
    <div
      className="flex h-9 w-full overflow-hidden rounded-md border border-black/10"
      aria-hidden="true"
      style={{ background }}
    >
      {/* Sidebar strip */}
      <div className="h-full w-5 shrink-0" style={{ background: sidebar }} />
      {/* Main area */}
      <div className="flex flex-1 flex-col justify-end gap-0.5 p-1">
        {/* Status bar strip */}
        <div className="h-1.5 w-full rounded-sm" style={{ background: statusBar }} />
      </div>
      {/* Accent dot */}
      <div className="flex items-start justify-end p-1">
        <div className="size-2 rounded-full" style={{ background: accent }} />
      </div>
    </div>
  );
}

// Half-and-half swatch for the "System" option
function SystemSwatch() {
  const light = BUILT_IN_THEMES.find((t) => t.id === "t3-light")!;
  const dark = BUILT_IN_THEMES.find((t) => t.id === "t3-dark")!;
  return (
    <div
      className="flex h-9 w-full overflow-hidden rounded-md border border-black/10"
      aria-hidden="true"
    >
      <div className="flex w-1/2 flex-col" style={{ background: light.colors.background }}>
        <div className="h-full w-4 shrink-0" style={{ background: light.colors.sidebar }} />
      </div>
      <div
        className="flex w-1/2 flex-col items-end"
        style={{ background: dark.colors.background }}
      >
        <div className="h-full w-4 shrink-0" style={{ background: dark.colors.sidebar }} />
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// ThemeSelector
// ---------------------------------------------------------------------------

export function ThemeSelector() {
  const { theme, themeId, setTheme } = useTheme();

  return (
    <div className="grid grid-cols-2 gap-2 sm:grid-cols-4" role="radiogroup" aria-label="Theme">
      {/* Built-in named themes */}
      {BUILT_IN_THEMES.map((builtIn) => {
        const selected = theme === builtIn.id;
        return (
          <button
            key={builtIn.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex flex-col gap-1.5 rounded-xl border p-2 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ${
              selected
                ? "border-primary/60 bg-primary/8 ring-1 ring-primary/30"
                : "border-border bg-background hover:border-border hover:bg-accent"
            }`}
            onClick={() => setTheme(builtIn.id as ThemePreference)}
          >
            <ThemeSwatch
              background={builtIn.colors.background}
              sidebar={builtIn.colors.sidebar}
              accent={builtIn.colors.accent}
              statusBar={builtIn.colors.statusBar}
            />
            <div className="flex items-center justify-between gap-1 px-0.5">
              <span className="text-xs font-medium text-foreground">{builtIn.name}</span>
              {selected && (
                <span className="rounded bg-primary/14 px-1 py-0.5 text-[9px] font-semibold uppercase tracking-wide text-primary">
                  On
                </span>
              )}
            </div>
          </button>
        );
      })}

      {/* System option */}
      {(() => {
        const selected = theme === "system";
        return (
          <button
            key="system"
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex flex-col gap-1.5 rounded-xl border p-2 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ${
              selected
                ? "border-primary/60 bg-primary/8 ring-1 ring-primary/30"
                : "border-border bg-background hover:border-border hover:bg-accent"
            }`}
            onClick={() => setTheme("system")}
          >
            <SystemSwatch />
            <div className="flex items-center justify-between gap-1 px-0.5">
              <span className="text-xs font-medium text-foreground">System</span>
              {selected && (
                <span className="rounded bg-primary/14 px-1 py-0.5 text-[9px] font-semibold uppercase tracking-wide text-primary">
                  On
                </span>
              )}
            </div>
          </button>
        );
      })()}
    </div>
  );
}

